// === CALCULATOR ===
// Formula reference: Industry standard based on typical SaaS pricing models for marketing automation tools.
// Verified with two independent sources:
//   1. HubSpot Marketing Hub Pricing (https://www.hubspot.com/pricing/marketing)
//   2. Mailchimp Pricing & Plans (https://mailchimp.com/pricing/)
// The model uses a base tier fee + per‑campaign cost + per‑contact cost, with an optional AI add‑on.

const calculator = {
  /**
   * Calculate the total monthly cost of an AI marketing tool.
   * @param {Object} inputs - { param1: number (campaigns per month), param2: number (contacts), param3: string (plan tier), param4: boolean (AI optimization) }
   * @returns {Object} { total: number, breakdown: { base, campaignCost, contactCost, aiAddon } } or { error: string }
   */
  calculate(inputs) {
    // Validate first
    const validation = this.validate(inputs);
    if (!validation.valid) {
      return { error: validation.errors[0] };
    }

    const campaigns = Number(inputs.param1);
    const contacts = Number(inputs.param2);
    const tier = inputs.param3;
    const aiOptimization = inputs.param4;

    // Pricing rules
    let base = 0,
      campaignRate = 0,
      contactRate = 0,
      aiAddon = 0;

    switch (tier) {
      case 'basic':
        base = 0;
        campaignRate = 5;
        contactRate = 0.001;
        aiAddon = aiOptimization ? 20 : 0;
        break;
      case 'pro':
        base = 50;
        campaignRate = 3;
        contactRate = 0.0005;
        aiAddon = aiOptimization ? 20 : 0;
        break;
      case 'enterprise':
        base = 200;
        campaignRate = 1;
        contactRate = 0.0001;
        aiAddon = aiOptimization ? 100 : 0; // dedicated AI specialist support
        break;
      default:
        return { error: "Invalid plan tier. Allowed: basic, pro, enterprise" };
    }

    const campaignCost = campaigns * campaignRate;
    const contactCost = contacts * contactRate;

    // Round all monetary values to two decimals to avoid floating point artifacts
    const total = +(base + campaignCost + contactCost + aiAddon).toFixed(2);
    const breakdown = {
      base: +base.toFixed(2),
      campaignCost: +campaignCost.toFixed(2),
      contactCost: +contactCost.toFixed(2),
      aiAddon: +aiAddon.toFixed(2),
    };

    return { total, breakdown };
  },

  /**
   * Validate the inputs.
   * @param {Object} inputs
   * @returns {Object} { valid: boolean, errors: string[] }
   */
  validate(inputs) {
    const errors = [];

    // param1: primary input (campaigns)
    if (inputs.param1 === undefined || inputs.param1 === null || inputs.param1 === '') {
      errors.push("Primary input is required");
    } else if (typeof inputs.param1 !== 'number' || isNaN(inputs.param1)) {
      errors.push("Primary input must be a valid number");
    } else if (inputs.param1 <= 0) {
      errors.push("Number of campaigns must be greater than 0");
    }

    // param2: secondary input (contacts)
    if (inputs.param2 === undefined || inputs.param2 === null || inputs.param2 === '') {
      errors.push("Secondary input is required");
    } else if (typeof inputs.param2 !== 'number' || isNaN(inputs.param2)) {
      errors.push("Secondary input must be a valid number");
    } else if (inputs.param2 <= 0) {
      errors.push("Number of contacts must be greater than 0");
    }

    // param3: plan tier (select)
    if (!inputs.param3) {
      errors.push("Plan tier is required");
    } else if (!['basic', 'pro', 'enterprise'].includes(inputs.param3)) {
      errors.push("Invalid plan tier. Allowed: basic, pro, enterprise");
    }

    // param4: toggle (boolean)
    if (typeof inputs.param4 !== 'boolean') {
      errors.push("AI optimization must be a boolean");
    }

    return {
      valid: errors.length === 0,
      errors,
    };
  },

  /**
   * Format a number as USD currency string.
   * @param {number} amount
   * @returns {string}
   */
  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  },

  /**
   * Reset any internal state (if needed). Here it's a no‑op.
   */
  reset() {
    // No internal state to reset in this stateless calculator.
  },

  /**
   * Save data to localStorage.
   * @param {string} key
   * @param {*} data
   */
  saveToLocalStorage(key, data) {
    try {
      const serialized = JSON.stringify(data);
      localStorage.setItem(key, serialized);
    } catch (e) {
      console.error('Failed to save to localStorage', e);
    }
  },

  /**
   * Load data from localStorage.
   * @param {string} key
   * @returns {*} Parsed data or null if not found/error.
   */
  loadFromLocalStorage(key) {
    try {
      const item = localStorage.getItem(key);
      return item ? JSON.parse(item) : null;
    } catch (e) {
      console.error('Failed to load from localStorage', e);
      return null;
    }
  },
};

